module RefModule(
    input clk,
    input clear_n,
    input [63:0] data_in,
    output reg [63:0] data_out
    );

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (!clear_n)
            data_out <= 64'b0;
        else
            data_out <= data_in;
    end
endmodule
